mapper.select:
SELECT COALESCE(SUM(o.total), 0)
FROM ORDERS o
    JOIN MEMBER m ON o.member_id = m.id
WHERE o.ordered_at BETWEEN #{from} AND #{to}
  AND o.status IN ('PAID', 'READY', 'SHIPPING', 'DONE')

      AND m.church_id = #{churchId}

SELECT COALESCE(SUM(d.amount), 0)
FROM DONATION d
    JOIN MEMBER m ON d.member_id = m.id
WHERE d.paid_at BETWEEN #{from} AND #{to}
  AND d.status = 'PAID'

      AND m.church_id = #{churchId}

SELECT COUNT(*)
FROM SUBSCRIPTION s
    JOIN MEMBER m ON s.member_id = m.id
WHERE s.started_at BETWEEN #{from} AND #{to}

      AND m.church_id = #{churchId}

SELECT t.day AS date, COALESCE(SUM(t.goods_revenue), 0) AS goods_revenue, COALESCE(SUM(t.recurring_donation), 0) AS recurring_donation, COALESCE(SUM(t.once_donation), 0) AS once_donation FROM ( SELECT DATE_FORMAT(o.ordered_at, '%Y-%m-%d') AS day, o.total AS goods_revenue, 0 AS recurring_donation, 0 AS once_donation FROM ORDERS o JOIN MEMBER m ON o.member_id = m.id WHERE o.ordered_at BETWEEN #{from} AND #{to} AND o.status IN ('PAID', 'READY', 'SHIPPING', 'DONE')
AND m.church_id = #{churchId}
UNION ALL SELECT DATE_FORMAT(d.paid_at, '%Y-%m-%d') AS day, 0 AS goods_revenue, CASE WHEN d.type = 'SUBSCRIPTION' THEN d.amount ELSE 0 END AS recurring_donation, CASE WHEN d.type = 'ONCE' THEN d.amount ELSE 0 END AS once_donation FROM DONATION d JOIN MEMBER m ON d.member_id = m.id WHERE d.paid_at BETWEEN #{from} AND #{to} AND d.status = 'PAID'
AND m.church_id = #{churchId}
) t GROUP BY t.day ORDER BY t.day

SELECT u.source_id AS source_id, u.kind AS kind, u.status AS status, u.amount AS amount, m.name AS member_name, u.occurred_at AS occurred_at FROM ( SELECT o.id AS source_id, 'ORDER' AS kind, o.status AS status, o.total AS amount, o.member_id AS member_id, o.ordered_at AS occurred_at FROM ORDERS o UNION ALL SELECT s.id AS source_id, 'SUBSCRIPTION' AS kind, s.status AS status, NULL AS amount, s.member_id AS member_id, s.started_at AS occurred_at FROM SUBSCRIPTION s UNION ALL SELECT d.id AS source_id, 'DONATION' AS kind, d.type AS status, d.amount AS amount, d.member_id AS member_id, d.paid_at AS occurred_at FROM DONATION d WHERE d.status = 'PAID' UNION ALL SELECT mm.id AS source_id, 'MEMBER' AS kind, mm.user_status AS status, NULL AS amount, mm.id AS member_id, mm.created_at AS occurred_at FROM MEMBER mm ) u JOIN MEMBER m ON u.member_id = m.id
WHERE m.church_id = #{churchId}
ORDER BY u.occurred_at DESC, u.source_id DESC LIMIT #{limit}
